var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......유미나?","JPN":"……ヤナギ・ミナ？","ENG":"Yoo Mina?","TWN":"……劉米娜。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"비, 비숍?!","JPN":"ビ、ビショップ！？","ENG":"B-Bishop!","TWN":"大、大主教？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어째서 여기에......?","JPN":"どうしてここに……？","ENG":"Why are you here?","TWN":"妳怎麼會在這裡……？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 아직도 리플레이서에게 협력하고 있는 거야?","JPN":"まさか、今でもリプレイサーに協力してるの？","ENG":"Are you still cooperating with the Replacers?","TWN":"難道妳現在還在幫助克隆集團嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"너무 그렇게 윽박지르지 말게.","JPN":"そう迫るな。","ENG":"Don't yell at her too much.","TWN":"別嚇她了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그녀는 아직 어려. 주변의 압력을 이겨내고 자기 생각을 솔직하게 말하기엔 조금 이르지.","JPN":"彼女はまだ若い。\\n周りの目を気にせず、自分の考えを正直に話すのはまだ早いだろう。","ENG":"She's still young. She's not mature enough to express her honest opinions without being affected by outside pressures.","TWN":"她還年輕，要她克服周圍的壓力，坦率說出自己的想法還太早了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다, 당신은?! 그때 그 홀로그램에서 본......!!","JPN":"あ、あなたは！？　あの時のホログラムに出てた……！！","ENG":"Y-you! I saw you in the hologram!","TWN":"你、你是？！那個時候在全息影像看到的……！！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"당신이...... 바로 리플레이서 킹이군요.","JPN":"あなたが……リプレイサー・キングなんですね。","ENG":"You're the Replacer King.","TWN":"你就是……克隆．帝皇啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"실비아 양이 속한 델타세븐의 전 부사령관이었다는......","JPN":"シルビアさんがいるデルタセブンの元副司令官だったという……","ENG":"The former deputy commander of Delta Seven, where Sylvia now works.","TWN":"希爾維亞小姐所屬的第七三角洲部隊前副司令官……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"안타깝지만...... 이제는 지나간 옛 이야기지.","JPN":"残念ながら……もう昔の話だ。","ENG":"Ah, they're fond memories, but that was ages ago.","TWN":"很遺憾……那都是過去的事情了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그보다, 뉴 오하이오에 승선한 것을 환영하네.","JPN":"それより、ニューオハイオへの乗船を歓迎しよう。","ENG":"Anyway, welcome aboard the New Ohio.","TWN":"歡迎你們登上新俄亥俄。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"직접 만나는 건 처음이지만, 자네들의 이름은 그동안 나도 많이 들었지.","JPN":"初対面だが、君たちの名は聞きなれている。","ENG":"It's my first time meeting you, but I've heard your names many times over.","TWN":"雖然我們是第一次見面，但你們的名字我很常聽到。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"우리 간부들이 자네들 덕분에 꽤나 고생했다고 하더군.","JPN":"うちの幹部たちが、君たちのおかげでずいぶん苦労したと言っていたな。","ENG":"My officers say you gave them a hard time.","TWN":"聽說我們的幹部因為你們，吃了很多苦頭呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"대단해. 이건 가감 없는 내 진심일세.","JPN":"すごいな。これは私の素直な感想だ。","ENG":"That's impressive. I mean it, I'm truly impressed.","TWN":"真厲害，這是我發自內心的話語。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"일을 벌인 내가 할 말은 아니지만, 어린 나이에 험한 사건들을 겪으면서 꽤나 시련이 많았을 것 같은데......","JPN":"この事態を作った私の言うことではないが、\\n若くして散々な目に遭って大変だったと思うが……","ENG":"I'm the one who started all this, so it might be awkward coming from me, but you've experienced so many hardships at such a young age...","TWN":"雖然是我惹的事端，這話不該由我來說，但是妳小小年紀就經歷這麼險惡的事情，恐怕通過很多的試煉吧……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"결국 그 모든 것들을 극복하고 누구보다 먼저 내 앞에 도달했군.","JPN":"ついにその全てを乗り越え、誰よりも早く私のもとへたどり着いた。","ENG":"And you overcame everything to come stand in front of me before anyone else did.","TWN":"但是妳最終還是克服了這一切，比誰都還要先來到我的面前。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네들은 내 환영을 받을 만한 가치가 있어. 다시 한 번 환영하네.","JPN":"君たちには私の歓迎を受ける資格がある。改めて、歓迎する。","ENG":"You both deserve my warm welcome. Again, welcome aboard.","TWN":"妳值得接受我的歡迎。我要在這裡再次歡迎妳。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"집어치워!","JPN":"いい加減にして！","ENG":"You're crazy!","TWN":"夠了！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고생했다고? 환영한다고? 그게 다 무슨 개소리야?!","JPN":"大変だった？　歓迎する？　冗談じゃないよ！？","ENG":"Hardships? A warm welcome? Are you trying to be funny now?","TWN":"辛苦？歡迎我們？你說這什麼鬼話啊？！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그동안 우리가 당신과 술래잡기라도 하고 있었던 것 같아?","JPN":"これまで私たちと、鬼ごっこでもしてきたつもり？","ENG":"You talk like we've been playing hide and seek with you.","TWN":"你以為我們這段時間在和你玩捉迷藏嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신이 무슨 짓을 했는지는 알고 있어?","JPN":"あんたが何をしでかしたか、わかってるの？","ENG":"Are you aware of what you've been doing all this time?","TWN":"你知道你做了什麼事情嗎？"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신 때문에 고통 받은 사람들이 대체 얼마나 되는지 아느냐고!!","JPN":"あんたのせいで苦しんでる人の数を、知ってるのかって聞いてんの！！","ENG":"Do you know how many people had to suffer because of you?","TWN":"你知不知道因為你，有多少人陷入痛苦之中啊！"},"stage":{"bg":"MAINSTREAM_412010","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 고작 하는 소리가...... 그거야?","JPN":"他に言うこと……あるんじゃないの？","ENG":"And that's what you have to say after all you've done?","TWN":"結果你想說的……就這樣？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>의도치 않게</color> 따위의 말로 자네들을 기만하지는 않겠네.","JPN":"<color=#ffd34c>不本意ながら</color>なんて言葉で、君たちのことを欺くつもりはない。","ENG":"I won't insult you by saying <color=#ffd34c>I didn't mean it</color>.","TWN":"我不想用<color=#ffd34c>不是故意</color>之類的話欺騙你們。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네들이 받은 고통에 대해서는 정말로 유감이지만...... 난 나의 행동을 후회하거나 번복할 생각은 없어.","JPN":"君たちの辛い経験については、実に残念に思うが……\\n私は自分の行動を悔いたり、考えを改めるつもりはない。","ENG":"I'm truly sorry for all the pain that you had to suffer, but by no means do I regret my past actions.","TWN":"對於你們的痛苦，我感到很遺憾……但我不後悔，也不會顛覆我的作為。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나래를 그런 꼴로 만들고 저런...... 복제품으로 사람을 농락하면서도 후회하지 않는다고?","JPN":"ナルミをあんな目に遭わせて、あんな……レプリカで人を翻弄させたのに、悔いはないって？","ENG":"You ruined Narae's life, and you mocked her death by creating her clone. And you don't regret it?","TWN":"把娜拉變成那個鬼樣子……用克隆把人類玩弄在手中，你都不後悔嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 뭣 때문에 이런 짓을 하는 거야?","JPN":"いったい何のためにこんなことをしてるの？","ENG":"Why are you doing this?","TWN":"到底是為了什麼，要做出這種事情？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"말해 봐! 이유라도 있을 거 아냐?!","JPN":"言ってよ！　理由があるんでしょ！？","ENG":"Tell me. You must have a reason!","TWN":"告訴我！總有個理由吧？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이유라......","JPN":"理由か……","ENG":"Reason...","TWN":"理由……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"여러 가지가 있지만 굳이 하나를 꼽자면......","JPN":"色々あるが、あえて一つ挙げるとしたら……","ENG":"There are a few, but to pick one...","TWN":"有很多，非要舉出一個的話……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래, 우주가 너무 넓기 때문이라고 하면 어떨까?","JPN":"そうだな、宇宙が広すぎるから、というのはどうだ？","ENG":"Yes, how about I do it because the universe is too vast?","TWN":"好吧，那說因為宇宙太寬廣了怎麼樣？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"えっ……？","ENG":"What?","TWN":"什……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 무슨 헛소리야? 지금 나랑 장난하자는 거야?!","JPN":"そんな冗談言ってる場合？　ふざけてるの！？","ENG":"You've got to be kidding me. Is this a joke to you?","TWN":"這是什麼鬼話？你在和我開玩笑嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"헛소리가 아닐세. 진심이지.","JPN":"冗談ではない、本心だ。","ENG":"No, it's not a joke. I'm being serious.","TWN":"這不是鬼話，我是認真的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"만약 우주가 조금만 더 좁았다면......","JPN":"もし宇宙がもう少し狭かったなら……","ENG":"If the universe were a little bit smaller...","TWN":"要是宇宙能小一點的話……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래서 인류가 다른 행성으로 도망갈 수 있다는 아주 약간의 희망이라도 있었다면, 나도 이런 극단적인 방법을 쓰지는 않았을 테지.","JPN":"それで人類が別の惑星へ避難できるという、ごくわずかな希望さえ持てたなら、\\n私もこんな極端な手段は使わなかっただろう。","ENG":"and there were a tiny bit of hope that mankind could escape to another planet, I wouldn't have taken these extreme measures.","TWN":"那麼人類就有逃到其他行星、非常微小的一絲希望，我也就不會使用這種極端的方法了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 행성? 도망을 간다......?","JPN":"別の惑星？　避難……？","ENG":"Escape to another planet?","TWN":"其他行星？逃跑……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만...... 현실은 가혹하지.","JPN":"だが……現実は厳しい。","ENG":"However... the reality is harsh.","TWN":"但是……現實很殘酷。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이터니움 드라이브가 실용화된 현재의 우주항해 기술로도 가장 가까운 프록시마 센타우리까지 최소한 10만년 이상이 걸려.","JPN":"エタニウムドライブが実用化した現在の宇宙航海技術でも、\\n最も近いプロキシマ・ケンタウリまで、最低でも10万年以上かかる。","ENG":"The space technology has advanced to the point that we're utilizing Eternium Drive to power our ships, but it still takes at least a hundred thousand years to get to Proxima Centauri.","TWN":"即使是在現在，以永恆之金引擎實用化的宇宙航行技術，我們要到達最近的比鄰星，最少也會拖個10萬年以上。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"SF 소설에는 수백만 년을 항해하는 세대 우주선의 이야기도 흔하게 나오지만......","JPN":"SF小説には数百万年を航海する宇宙船の話も頻繁に登場するが……","ENG":"Science fiction tells of space ships that navigate for millions of years,","TWN":"儘管科幻小說中經常出現航行數百萬年的世代太空船……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"실제로 인류는 백 년 동안 동작하는 기계도 만들어 본 적이 없네.","JPN":"実際には、人類は百年間作動する機械すら創り出したことがない。","ENG":"but in reality, mankind hasn't even made a single mechanical part that continues working for a hundred years,","TWN":"但是實際上，人類連能夠運轉一百年的機器都沒造出來過。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하물며 수십만 년을 오차 없이 날아가야 하는 우주선은 말할 것도 없지.","JPN":"ましてや、数十万年を誤差なく飛ばなければならない宇宙船は言うまでもない。","ENG":"let alone a space ship sturdy enough to last a hundred thousand-year journey.","TWN":"更何況是要無誤差地航行數十萬年的太空船。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"심지어는 그렇게 도착한 곳에 인류가 살 만한 행성이 있다고 확신할 수 있는 것도 아니야.","JPN":"しかも、もしたどり着いたとしても、そこに人類が生き延びれる惑星があるとは限らない。","ENG":"Worse, even if we were to make it there in one piece, there's no guarantee that there would be a planet with a habitable environment.","TWN":"再加上，我們也無法確定到達的地方，是不是人類可以居住的行星。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이래서야...... 전혀 희망이 없다고 해야 하지 않겠나?","JPN":"これでは……まったくもって希望がないじゃないか。","ENG":"This is a truly hopeless situation for all of us.","TWN":"這樣……我們不就是毫無希望嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨...... 무슨 소릴 하는 거야?!","JPN":"なに……何言ってんの！？","ENG":"W-what on earth are you talking about?","TWN":"你……你在說什麼啊？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우주 항해니, 프록시마 센타우리니...... 하나도 못 알아듣겠어!!","JPN":"宇宙航海とか、プロキシマ・ケンタウリとか……さっぱりわからないよ！！","ENG":"Space ships, Proxima Centauri... I don’t understand any of it!","TWN":"什麼宇宙航行、比鄰星……我一個字都聽不懂！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 당신이 저지른 만행과 무슨 상관이냐고!!","JPN":"それがあなたのしてきたことと、何の関係があるのよ！！","ENG":"What do these things have do with your atrocities?","TWN":"這些和你犯下的暴行又有什麼關係！！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그야 곧 종말이 닥쳐올 테니까.","JPN":"それは、まもなく終末がおとずれるからな。","ENG":"Everything. Doomsday is coming.","TWN":"末日就要到來了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐?","JPN":"な、なに？","ENG":"W-what?","TWN":"什、什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"종말?","JPN":"終末？","ENG":"Doomsday?","TWN":"末日？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래, 종말이 다가오고 있다.","JPN":"そうだ、終末が近づいている。","ENG":"Yes, it's coming.","TWN":"沒錯，末日就要來了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"막을 수도, 피할 수도 없는 절대적인 종말이......","JPN":"防ぐことも、避けることもできない、絶対的な終末が……","ENG":"And it can't be stopped or avoided.","TWN":"無法阻止也無法逃避的絕對末日……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨...... 사이비나 믿을 것 같은 거짓말을......","JPN":"そんな……宗教じみた嘘を……","ENG":"That's a pathetic lie that only brainless cult followers would fall for.","TWN":"這是什麼……傻子才會信的謊話。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"거짓말이 아닐세. 내가 대정화 전쟁 참전자라는 건 알고 있겠지?","JPN":"嘘ではない、私が大浄化戦争に参戦していたことは知ってるだろう？","ENG":"I'm not lying. You know I fought in the Grand Purification War, don't you?","TWN":"不是謊話。妳知道我是淨化之戰的參戰者吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"전쟁에 참전하는 동안 난 일종의 정보장교 역할을 맡았었네.","JPN":"戦時中、私は情報将校のような役割をしていた。","ENG":"During the war, I served as an intelligence officer.","TWN":"參戰的時候，我擔任的是某種情報將校。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이면세계에 남겨진 다양한 정보와 기록들을 수집해서 침식체들에 대항할 방법을 찾는 그런 일이었지.","JPN":"裏世界に残された様々な情報や記録を収集し、侵食体の対応策を探す仕事だった。","ENG":"I was in charge of collecting various information and records from the Counterside to find a way to deal with the C.O.s.","TWN":"我負責收集和異界有關的各種情報和紀錄，然後找出對抗侵蝕體的方法。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만...... 그 일을 진행하면서 난 전혀 예상하지 못한 다른 진실을 알아버리고 말았네.","JPN":"だが……私はその仕事中に、まったく想定外の、別の真実を知ってしまったんだ。","ENG":"But... through my operations, I came to learn a truth, and a very unexpected one at that.","TWN":"但是……在我執行任務的同時，我發現了我完全沒有預想到的真相。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전혀 다른 진실이라...... 그게 뭐죠?","JPN":"まったく想定外の真実……それは何でしょう？","ENG":"An unexpected truth, huh... What was it?","TWN":"完全沒有預想到的真相……那是什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네들은 이면세계가 뭐라고 생각하나?","JPN":"君たちは裏世界のことを何だと思ってる？","ENG":"What do you think the Counterside is?","TWN":"你們覺得異界是什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"어째서 이면세계에는 마치 인간이 만든 것 같은 버려진 도시와 유적들이 존재하는 거지?","JPN":"どうして裏世界には、まるで人間が建てたような都市や遺跡が放置されているんだ？","ENG":"Why are there abandoned cities and ruins that look like they were built by mankind?","TWN":"為什麼異界裡會有像是人類建造的廢棄都市和遺跡呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건......","JPN":"それは……","ENG":"That's...","TWN":"這……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그건 이면세계가 바로 멸망한 세계의 잔재이기 때문이다.","JPN":"それはつまり、裏世界が滅亡した世界の残骸だからだ。","ENG":"It's because the Counterside is the vestiges of the worlds that existed before.","TWN":"因為異界就是滅亡的世界殘餘。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐...... 라고?","JPN":"……は？","ENG":"W-what did you say?","TWN":"你說……什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그것도 한 번, 두 번이 아니야.","JPN":"しかも、一回や二回ではない。","ENG":"And it hasn't happened just once.","TWN":"那也不是一兩次的事情。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"다양한 심도와 좌표로 나뉘어진 이면세계들......","JPN":"様々な深度や座標で分かれている裏世界……","ENG":"There are several Counterside worlds at different depths and coordinates,","TWN":"被分為不同深度和座標的異界……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그것들 각각이 모두 별개의 멸망한 세계들이지.","JPN":"それらすべてが、滅亡した個別の世界だ。","ENG":"and every single one of them is a world after the apocalypse.","TWN":"它們各自就是不同的滅亡世界。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그중에는 우리와 극히 비슷한 문명도, 전혀 다른 문명도 있지만......","JPN":"なかには我々と酷似している文明も、まったく別の文明もあったが……","ENG":"Some of them had civilizations similar to ours, and some different,","TWN":"在那之中，有和我們極其相似的文明，也有完全不一樣的文明……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그 어떤 세계도 멸망하여 <color=#ffd34c>이면화</color>되는 운명을 피할 수 없었어.","JPN":"いずれの世界も、滅亡して<color=#ffd34c>裏世界化</color>する運命から逃れることはできなかった。","ENG":"but none of them were able to escape the doom that came before the <color=#ffd34c>Counterization</color>.","TWN":"不管是什麼樣的世界，都無法避免滅亡後<color=#ffd34c>異界化</color>的命運。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그리고 이제는...... 우리 차례가 다가오고 있다.","JPN":"そして今度は……私たちの番が近づいている。","ENG":"And now, the end is coming to our world.","TWN":"然後現在……快要輪到我們了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서...... 도망칠 방법을 구상한 겁니까?","JPN":"それで……逃げる方法を考えたのですか？","ENG":"And... you were trying to devise a plan to flee?","TWN":"所以……你想出逃跑的方法了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서는 그 방법의 일부인 거고?","JPN":"リプレイサーは、その方法の一部だと？","ENG":"And creating the Replacers was a part of it?","TWN":"克隆集團就是那個方法的一部分？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Precisely.","TWN":"是的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이 세계는 곧 멸망한다. 하지만 우주로 도망칠 수는 없지. 그건 불가능하니까.","JPN":"この世界はもうじき滅亡する。だが、宇宙に逃げることは不可能だ。","ENG":"This world will end soon. And we can't flee to outer space. Our technologies are just not advanced enough.","TWN":"這個世界馬上會滅亡，但是我們又無法逃向宇宙，因為那是不可能的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래서 나는...... 이면세계로 도망치기로 했다.","JPN":"そこで私は……裏世界に逃げることにしたんだ。","ENG":"So I decided that the Counterside would be our shelter.","TWN":"所以我決定……逃往異界。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그곳이야말로 인류가 현실적으로 도달할 수 있는 유일한 피난처니까.","JPN":"そこは、人類が実際に到達できる、唯一の避難先だからな。","ENG":"Because that was the only place left for mankind to go.","TWN":"那是人類在現實中，可以到達的唯一避難所。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만 이 계획에는 문제가 있지.","JPN":"だが、この計画には問題がある。","ENG":"But my plan had a flaw.","TWN":"但是這個計畫也存在著問題。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"인간은 이면세계에서 장시간 버티지 못해.","JPN":"人間は裏世界で長時間耐えられないんだ。","ENG":"We can't last long in the Counterside.","TWN":"人類無法長時間待在異界。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이터니움 실드 같은 장치를 쓴다고 해도 어차피 임시방편일 뿐이지......","JPN":"エタニウムシールドのような装置を使うとしても、どうせその場しのぎでしかない。","ENG":"Relying on devices like Eternium shields is just a temporary measure.","TWN":"使用永恆之金護盾也只是一時的權宜之計。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"시간이 지나면 인간은 결국 침식체로 붕괴해 버린다.","JPN":"時間が経てば、人間は結局、侵食体になってしまうのだ。","ENG":"As time passes, humans beings are bound to collapse into Corrupted Objects.","TWN":"隨著時間的流逝，人類終究會崩壞成侵蝕體。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래서 나는 리플레이서 인자를 만들었다.","JPN":"だから、私はリプレイサーファクターを作った。","ENG":"That was why I created the Replacer Factor.","TWN":"所以我做出了克隆因子。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 리플레이서 인자는 전투용이 아니었군요.","JPN":"やはりリプレイサーファクターは、戦闘のためではなかったのですね。","ENG":"So it was never meant to be used for combat.","TWN":"果然克隆因子不是用於戰鬥的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마도 그 목적은...... 이면세계에서도 살아남을 수 있는 인간 변이체를 만드는 것.","JPN":"たぶんその目的は……裏世界でも生き残れる人間の変異体を作ること。","ENG":"It was a part of the plan to cause a mutation that would help mankind adjust to the environment of the Counterside.","TWN":"那個目的大概……是為了創造出可以在異界中活下來的人類變異體。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......정답이네.","JPN":"……正解だ。","ENG":"You're correct.","TWN":"……正確答案。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만 여기에도 문제가 발생했지.","JPN":"だが、ここでも問題が生じた。","ENG":"But soon I ran into another problem.","TWN":"但是這裡也出現了問題。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 융합체는 안정적이지 못해.","JPN":"リプレイサー融合体は安定した存在ではなかったんだ。","ENG":"Replacer hybriders weren't stable enough.","TWN":"克隆融合體無法保持穩定。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"지속적으로 메인터넌스를 위한 리플레이서 인자를 추가 투여하지 않으면 결국 침식체나 다름없는 붕괴체로 바뀌어 버린다.","JPN":"メンテナンスのためのリプレイサーファクターを継続投与しないと、\\n結局侵食体同然の崩壊体に変わってしまう。","ENG":"We had to provide them with Replacer Factors regularly, or they would turn into Collapsers, and Collapsers are barely better than C.O.s.","TWN":"如果不持續投入額外維護用的克隆因子，人類最終還是會變成侵蝕體或沒差多少的崩壞體。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"안정적으로 융합 상태를 유지할 수 있는 얼터너티브 인자를 개발하긴 했지만......","JPN":"安定的に融合状態を維持できるオルタナティブファクターの開発には成功したが……","ENG":"We managed to develop the Alternative Factor, which guaranteed much better stability,","TWN":"即使我們開發出了可以維持穩定融合狀態的可替代因子……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이건 카운터 능력자에게만 이식할 수 있는데다가...... 그나마 적성체 비율이 너무 낮아서 사실상 의미가 없었지.","JPN":"これはカウンター能力者にしか移植できない上に……\\n適性体の確率が低すぎて、事実上、意味がなかった。","ENG":"but it could only be transplanted to a limited number of Counters who were physically receptive to it.","TWN":"但是這個只能移植於制裁者……而且就連適應體的比率也很低，幾乎沒有意義。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"계속 연구를 진행했다면 어쩌면 더 범용적인 결과물을 만들어낼 수 있었을지도 모르지만......","JPN":"研究を続けていれば、もしかしたら、より汎用的な結果を出せたかもしれないが……","ENG":"If we had been able to continue our research, the end result could have been more appropriate for universal use,","TWN":"如果我們繼續研究的話，應該可以製造出更為泛用的產物……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"유일한 이식 성공 실험체들이 모두 도망쳐 버린 터라 더 이상 연구를 지속할 수도 없었네.","JPN":"唯一、移植に成功した実験体がすべて逃げ出してしまったから、\\nそれ以上研究を続けることもできなかった。","ENG":"but the subjects of our only successful transplant test had run away and we had nothing to work with.","TWN":"但是唯一移植成功的實驗體全都逃跑了，研究已經無法繼續了。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"성공 실험체라면...... 서윤과 알트소대를 말하는 건가?","JPN":"成功した実験体って……シズカとアルト小隊のこと？","ENG":"By subjects, do you mean Seo Yoon and the ALT Squad?","TWN":"成功的實驗體……你是說徐芸和阿爾特小隊嗎？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래, 그 아이들이지. 우리가 그 아이들을 계속 찾았던 이유이기도 하고.","JPN":"そうだ。だからこそ、我々はその子たちを探していた。","ENG":"Yes. That's why we were looking everywhere for them.","TWN":"沒錯，就是那些孩子。這就是我們一直在找那些孩子的理由。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만 더 이상 그럴 필요가 없어졌네. 왜냐하면 자네가 나타났기 때문이지.","JPN":"だが、もうそんな必要はない。なぜなら、君が現れたからな。","ENG":"But then it was no longer necessary, because we found you.","TWN":"但是已經沒必要繼續找了。因為妳出現了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"유미나.","JPN":"ヤナギ・ミナ。","ENG":"Yoo Mina.","TWN":"劉米娜。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나, 나?","JPN":"わ、私？","ENG":"M-me?","TWN":"我、我？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래. 종말의 씨앗, 진정한 초월 변이인자의 블루프린트.","JPN":"そうだ。終末の種であり、真の超越変異ファクターの設計図。","ENG":"Yes. The seed of apocalypse, the blueprint of the true Transcendental Mutation Factor...","TWN":"沒錯。末日的種子，真正超越變異因子的藍圖。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"클리포트 인자의 보유자가 나타난 거지.","JPN":"クリフォト・ファクターの保持者が現れたのだ。","ENG":"The Qliphoth Factor carrier.","TWN":"逆卡巴拉因子的擁有者出現了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면......","JPN":"それって……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잃어버린 얼터너티브 인자의 개량 대신 클리포트 인자를 복제하기로 했군요.","JPN":"失ったオルタナティブ・ファクターの改良の代わりに、\\nクリフォト・ファクターを複製することに決めたんですね。","ENG":"You decided to copy the Qliphoth Factors rather than improving the lost Alternative Factors.","TWN":"你們沒有改良遺失的可替代因子，而是選擇複製逆卡巴拉因子了吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그래. 리플레이서 인자는 원래 북극점 공방전에 등장한 제 5종 침식체,","JPN":"そのとおりだ。リプレイサーファクターは元々北極点攻防戦に登場した、第5種侵食体。","ENG":"Yes. The Replacer Factor is actually an imitation of the core Eternium we found from the Nameless One,","TWN":"沒錯。克隆因子本來就是模仿北極點攻防戰中，登場的第5級侵蝕體——"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"네임리스 원의 코어 이터니움을 모방하여 만들어낸 거다.","JPN":"ネームレスワンのコアエタニウムを真似て作りだしたものだ。","ENG":"the Category 5 C.O. that appeared during the North Pole Battle.","TWN":"無名1的核心永恆之金做出來的"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"유실된 부분이 많기 때문에 열화 복제품인 리플레이서 인자로는 원본 코어 구조를 완전히 재현해낼 수 없었지만,","JPN":"欠けている部分が多く、劣化版のレプリカであるリプレイサーファクターでは、\\n原本のコア構造の完全再現はできなかったが、","ENG":"The core had already been disfigured when we started out, and being the crude copy that it was, the Replacer Factors couldn't be used to reproduce the structure of the original core.","TWN":"雖然因為遺失的部分太多，作為劣化複製品的克隆因子無法完全再現原本的核心構造……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"결손된 구조를 클리포트 인자로 대체한다면......","JPN":"一部欠けている部分をクリフォト・ファクターで代替することができれば……","ENG":"But if we could use Qliphoth Factors to plug all the holes,","TWN":"但缺損的部分如果用逆卡巴拉因子替代的話……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"인간을...... 네임리스 원과 같은 제 5종 침식체로 진화시킬 수 있게 된다.","JPN":"人間を……ネームレスワン同然の第5種侵食体に進化させることができる。","ENG":"we'd be able to turn a human into a Category 5 C.O. like the Nameless One.","TWN":"就可以讓人類……進化成第5級侵蝕體。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?!","JPN":"な、何だって！？","ENG":"W-what?","TWN":"什、什麼？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게 무슨 소리야?! 인간이 침식체로 붕괴하는 걸 막기 위해 리플레이서 인자를 만들었다면서?","JPN":"どういうこと！？　人間が侵食体になるのを防ぐために、リプレイサーファクターを作ったんでしょ？","ENG":"You're talking nonsense! You just said you created the Replacer Factor to keep humans from collapsing into C.O.s,","TWN":"這是什麼意思？！你不是是為了阻止人類崩壞成侵蝕體，才做出的克隆因子嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데 인간을 다시 5종 침식체로 진화시킨다니...... 앞뒤가 안 맞잖아?!","JPN":"なのに、人間を第5種侵食体に進化させるなんて……矛盾してるじゃない！？","ENG":"and now you're talking about evolving humans into Category 5 C.O.s. That doesn't make any sense!","TWN":"但怎麼又要把人類進化成第5級侵蝕體……你這不是前後矛盾嗎？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"제 5종 침식체 네임리스 원은 일반적인 침식체와 다르다.","JPN":"第5種侵食体のネームレスワンは、通常の侵食体とは別物だ。","ENG":"The Nameless One, or the Category 5 C.O., is different from regular C.O.s.","TWN":"第5級侵蝕體無名1和一般的侵蝕體不一樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이성을 유지할 수도 있고, 침식 광기에 대한 내성도 어느 정도 기대할 수 있어.","JPN":"理性を保つこともできるし、侵食による狂気への耐性もある程度は期待できる。","ENG":"It's quite resistant to Corruption Frenzy, and does not lose its ability to reason.","TWN":"第5級侵蝕體可以保持理性，也可以期待它能對侵蝕發狂一定程度的耐性。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"충분하지는 않더라도 인류와 인류 문명을 존속시킨다는 목표는 달성할 수 있겠지.","JPN":"十分ではなくとも、人類や人類の文明を存続させるという目標は達成できるだろう。","ENG":"I don't believe it's a cure-all, but it'd be enough to let us achieve our goal and keep humanity and its civilization going.","TWN":"就算不夠完全，也可以達成人類和人類文明存續下去的目的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그리고 무엇보다도...... 이것이 종말이 도래하기 전에 시도해 볼 수 있는 유일한 방법이니까.","JPN":"そして何より……これは終末が訪れる前に試せる、唯一の方法なんだ。","ENG":"And more than anything, this is the last thing we can try before the end comes.","TWN":"而且最重要的……這是末日到來之前，可以嘗試的唯一辦法了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......설명이 하나 빠진 것 같네요.","JPN":"……一つ、説明が抜けているようですね。","ENG":"You're leaving out an important part.","TWN":"……你有一件事沒有解釋呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"인간을 제 5종 침식체로 진화시킨다고 해도...... 그게 모든 인간은 아니겠죠?","JPN":"人間を第5種侵食体に進化させるにしても……対象はすべての人間ではないですよね？","ENG":"You said you're going to evolve humans into Category 5 C.O.s, but you're not talking about all humans, are you?","TWN":"就算人類能進化成第5級侵蝕體……那也不是所有人類吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대체 몇 명이나 살려서 이면세계로 데려가실 생각이시죠?","JPN":"いったいどれだけの数を生かして、裏世界へ連れていくつもりですか？","ENG":"How many are you planning to take to the Counterside?","TWN":"你到底打算救幾個人，把他們帶進異界去呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"클리포트 레플리카 인자의 융합 적성체 비율은 그다지 높진 않다.","JPN":"レプリカ・クリフォト・ファクターの融合適性体の確率はそこまで高くない。","ENG":"There are only a small number of people who have enough receptivity to Qliphoth Replica Factors.","TWN":"逆卡巴拉複製因子的融合適應體比率不是很高。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"낙관적으로 잡는다면 10%...... 보수적으로 잡는다면 5% 정도라고 예측하고 있네.","JPN":"甘く見積もって10％……現実的に考えると、5％程度を想定している。","ENG":"Approximately 10%, and more like 5% if I'm being conservative.","TWN":"樂觀來看有10%……保守來看只有5%。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그것도 끝이 아니겠죠.","JPN":"それで終わりではないでしょうね。","ENG":"And it won't end just there.","TWN":"這還沒完。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"메인터넌스용 리플레이서 인자 정도는 지금처럼 붕괴체들을 생체공장으로 활용하여 조달할 수 있겠지만......","JPN":"メンテナンス用のリプレイサーファクターぐらいは、\\n今のように崩壊体を生体工場として活用すれば調達できるでしょうけど……","ENG":"You could secure enough supply of maintenance-purpose Replacer Factors using the collapsers as factories,","TWN":"維護用的克隆因子，雖然可以像現在這樣，把崩壞體帶進活體工廠來獲得……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 레플리카 인자를 생산하려면...... 그 정도로는 부족할 텐데요?","JPN":"レプリカ・クリフォト・ファクターを生産するには……それだけじゃ足りないのでは？","ENG":"but maintaining steady production of Qliphoth Replica Factors is a completely different story.","TWN":"但是想要生產逆卡巴拉複製因子……這還是不夠的吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네 말이 맞네.","JPN":"君の言うとおりだ。","ENG":"You're right.","TWN":"你說得沒錯。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"충분한 수율을 유지하려면 좀 더 극단적인 방법이 필요하지.","JPN":"十分な収率を保つためには、もっと極端な方法が必要だ。","ENG":"We'll have to resort to a rather extreme measure to produce enough for everyone.","TWN":"想要維持足夠的產量，就必須使用更加極端的方法。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"극단적인 공정?","JPN":"極端な方法？","ENG":"An extreme measure?","TWN":"極端的方法？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......대략 예상이 가는군요.","JPN":"……だいたい予想はつきますね。","ENG":"I think I know what it is.","TWN":"……我大概能猜到了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양. 여긴 리플레이서 총기함 뉴 오하이오입니다.","JPN":"ミナさん。ここは、リプレイサー総旗艦のニューオハイオです。","ENG":"Mina, this is the New Ohio, the flagship of the Replacer Syndicate.","TWN":"米娜小姐。這裡是克隆集團的武裝艦船新俄亥俄。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"주력 부대가 관리국 함대를 상대하러 갔다고 해도 기함 내에 방어병력이 전혀 없다는 건 아무래도 부자연스럽죠.","JPN":"主力部隊が管理局の艦隊の相手をしてるにしても、\\n旗艦のなかに防御部隊がまったくいないのは、不自然なことです。","ENG":"Their main forces may have left to fight the Administration fleet, but it makes no sense that they didn't leave a single guard here to defend their flagship.","TWN":"就算克隆集團的主力部隊去對付管理局的艦隊了，但司令艦內部完全沒有防禦兵力也太不合理了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 생각에는...... 이곳에 모여 있던 리플레이서 병력들은 모두 클리포트 레플리카 인자 제작을 위한 재료로 사용되었을 겁니다.","JPN":"僕が思うに……ここにいたリプレイサー兵の全てが、\\nレプリカ・クリフォト・ファクターを作るための材料になったのでしょう。","ENG":"My guess is, all the Replacers that were here were used as material for Qliphoth Replica Factors.","TWN":"我想……在這裡的克隆集團兵力，應該全部被當成製造逆卡巴拉複製因子的材料了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"생체 대사를 통해 조금씩 자가복제를 하는 대신, 육신을 구성하는 리플레이서 인자를 모조리 분해해서 단숨에 대량의 리플레이서 인자를 회수하는 거죠.","JPN":"生体代謝で少しずつ自己複製をする代わりに、肉体を構成する\\nリプレイサーファクターをすべて分解して、一気に大量のリプレイサーファクターを回収するんです。","ENG":"Instead of letting the Replacers slowly duplicate factors through metabolism, they chose to dismantle all the Replacer Factors comprising the Replacers' bodies to obtain a massive amount of them.","TWN":"比起透過活體代謝，一點點地進行自我複製，將構成肉身的克隆因子全部分解掉，就可以一口氣回收大量的克隆因子了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리야, 그게......?","JPN":"ど、どういうこと……？","ENG":"W-what do you mean?","TWN":"這是什麼意思啊……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까...... 자기 편까지 희생시켰다는 거야?","JPN":"つまり……味方まで犠牲にしたってこと？","ENG":"Are you saying that they've sacrificed the lives of their own?","TWN":"所以是說……他們連自己的部隊都犧牲了？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그...... 클리포트 인자인가 뭔가 하는 걸 만들려고?","JPN":"その……クリフォト・ファクターとやらを作るために？","ENG":"Just to produce this Qliphoth thing?","TWN":"……就為了製造逆卡巴拉因子或什麼的？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼...... 대체 몇 명이나 살아남는다는 거야?","JPN":"じゃあ……いったい何人生き残れるわけ？","ENG":"H-how many survivors can there be if this is what they have to go through?","TWN":"那麼……到底會有多少人活著呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"최종적으로는 전 세계 인구의 약 0.003% 정도겠지.","JPN":"最終的には、世界総人口のうち、約0.003％程度になるだろう。","ENG":"At the end, I would say about 0.003% of the current world population.","TWN":"最後大約會有全世界人口的0.003%吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나머지 사람들은...... 어떻게 되는 건데?","JPN":"残りの人は……どうなるの？","ENG":"And what happens to the rest?","TWN":"剩下的人們會……怎麼樣呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"안타깝지만...... 불가피한 희생이라고 생각한다.","JPN":"残念だが……やむを得ない犠牲だ。","ENG":"I'll just say plans like this are bound to cause collateral damage.","TWN":"很遺憾……他們會無可避免地被犧牲。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"미쳤군.","JPN":"どうかしてる。","ENG":"You're crazy.","TWN":"瘋了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"완전히 미쳤어. 너무 황당해서 화를 낼 생각도 안 들어.","JPN":"完全にイカれてるよ。あり得なさ過ぎて、怒る気にもなれない。","ENG":"This is absolute madness. I'm so shocked that I don't even feel angry.","TWN":"完全瘋了，瘋到我連氣都生不出來了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배, 저 헛소리를 더 듣고 있을 생각은 아니지?","JPN":"先輩、あんなふざけたことこれ以上聞くつもりないよね？","ENG":"Shiyoon, you're not going to keep listening to that crap, are you?","TWN":"前輩，你不會還想要聽這種垃圾話吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당장 박살내 버리자고.","JPN":"今すぐ倒しちゃおうよ。","ENG":"Let's just smash everything up.","TWN":"馬上把這裡毀掉吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"동감입니다만...... 그렇게 간단할 것 같진 않군요.","JPN":"同感ですが……そんなに簡単ではなさそうですね。","ENG":"I'd love to do that, but I'm afraid it won't be so easy.","TWN":"我有同感……但我想不會這麼簡單。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이해 받을 수 있을 거라 생각하진 않았지만...... 그래도 직접 들으니 씁쓸하군.","JPN":"理解してもらえるとは思わなかったが……それでも、直接言われたら寂しいな。","ENG":"I didn't think you'd understand, but it breaks my heart to actually hear it from you.","TWN":"雖然我不認為你們會理解……但直接聽到你們這麼說，還是讓人覺得很苦澀啊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"하지만 나도 물러설 생각은 없네.","JPN":"だが、私も引き下がるつもりはない。","ENG":"But I have no intention of backing off.","TWN":"但是我也沒有想要讓步的打算。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 간부들을 포함하여, 우리 모두 다 대의를 위한 죽음을 각오하고 있다.","JPN":"リプレイサー幹部を含め、我々全員は大義のための死を覚悟している。","ENG":"Everyone in the organization, including my officers and myself, is prepared to die for our cause.","TWN":"包括克隆集團的幹部，我們全都有為大義而死的覺悟。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"퀸도, 나이트도, 폰도 이미 자신의 영혼이 파괴되는 것을 감수하면서까지 저 밖에서 수없이 파괴와 재생을 반복하고 있으니까.","JPN":"クイーンも、ナイトも、ポーンも、すでに自分の魂が壊れるのを自覚しながら、\\n外で破壊と再生を繰り返している。","ENG":"You saw Queen, Knight, and Pawn. They are gladly letting their bodies be destroyed and reconstructed at the risk of their own souls.","TWN":"女皇也好，騎士也好，就連兵卒都接受了自己靈魂的毀壞，經歷了反覆不斷，無數次的破壞與再生。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"비숍, 최종 재배포까지 얼마나 남았지?","JPN":"ビショップ、最終再配布まであとどれくらいだ？","ENG":"Bishop, how long do we have left until the final redistribution?","TWN":"主教，離最終的再發送還剩多少？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......퀸으로부터 진화 피드백이 고속으로 이루어지고 있다.","JPN":"……クイーンから、進化のフィードバックが高速で行われている。","ENG":"There's a massive amount of evolutionary feedback coming from Queen.","TWN":"……從女皇那裡接收的進化反饋正以高速進行著。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"현재 리플레이서 레플리카 인자 최종 재배포 버전 조합 완료율은...... 92.1%","JPN":"現在、レプリカ・クリフォト・ファクターによる、最終再配布版の組み合わせ完了率は……92.1％。","ENG":"The current completion rate of the final redistributable version of Replacer Replica Factor is... 92.1%","TWN":"現在，克隆複製因子最終再發送版本的組合達成率……92.1%"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"최종 재배포 버전......?","JPN":"最終再配布版……？","ENG":"The final redistributable version?","TWN":"最終再發送版本……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마도 스스로 퍼져나가면서 자가복제를 진행하는 클리포트 레플리카 인자를 말하는 걸 겁니다.","JPN":"たぶん、自ら広がって自己複製を行うレプリカ・クリフォト・ファクターのことだと思います。","ENG":"I bet it means the Qliphoth Replica Factor that's capable of spreading and duplicating itself.","TWN":"大概是在說一邊自我散播，一邊進行自我複製的逆卡巴拉複製因子吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이미 리플레이서 인자에 감염된 사람이 전 세계에 퍼져 있는 이상, 한 번 배포되게 되면 설사 이들을 쓰러트린다고 해도 연쇄반응을 막을 수 없을 겁니다.","JPN":"すでにリプレイサーファクターに感染した人間が世界中にいる以上、\\n一度広まってしまったら、たとえこの者たちを倒したとしても連鎖反応は防げないでしょうね。","ENG":"People infected by the Replacer Factors are spread all over the world. Once this gets distributed, there's going to be a devastating aftermath even if we manage to defeat them.","TWN":"被克隆因子感染的人已經遍佈全世界的情況下，如果再被發送一次，就算我們打敗了他們，也無法阻止連鎖反應了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?","JPN":"ほ、ほんとに？","ENG":"That's crazy!","TWN":"什、什麼？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그 말대로다.","JPN":"そのとおりだ。","ENG":"The boy's right.","TWN":"說得沒錯。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"설명은 이 정도면 충분히 한 것 같군. 그러니 제안을 하나 하지.","JPN":"説明はこれくらいで十分だろう。では、一つ提案しよう。","ENG":"I've given you enough explanations, I guess. Now, I'm going to make an offer.","TWN":"看來我解釋到這個程度，已經夠充分了。那麼我有一個建議。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그동안 보여 준 실력과 잠재력으로 추측하건대......","JPN":"これまで披露してくれた実力や潜在能力からして……","ENG":"Considering what you've shown me and the latent abilities that you have within you...","TWN":"根據這段時間以來，你們展現出的實力和可能性……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네들이라면 분명 <color=#ffd34c>살아남는 쪽</color>에 속할 수 있을 거라고 생각한다.","JPN":"君たちならきっと、<color=#ffd34c>生き残るほう</color>に入るだろう。","ENG":"I'm sure that you'll belong among the <color=#ffd34c>survivors</color>.","TWN":"我認為你們一定是屬於<color=#ffd34c>活下來的</color>那一邊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그러니 이곳에서 무익하게 나와 싸우는 대신 클리포트 레플리카 인자를 이식 받고, 이후 이면세계로 이주할 인류를 도울 생각이 있는지 묻고 싶군.","JPN":"だから、ここで私と無益な戦いをする代わりに、レプリカ・クリフォト・ファクターの移植を受けて、\\nいずれ裏世界へ移住する人類を助けるつもりはあるか確認したい。","ENG":"So I'd like to ask if you're willing to have the Qliphoth Replica Factors transplanted on you and help mankind migrate to the Counterside instead of fighting a meaningless battle against me here.","TWN":"所以比起在這裡進行沒有意義的戰鬥，不知道你們想不想接受逆卡巴拉複製因子的移植，幫助之後移居到異界的人們。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"헛소리! 그게 네 마음대로 될 것 같아?","JPN":"ふざけるな！　あんたの思い通りになるとでも思った？","ENG":"Nonsense! That's never going to happen!","TWN":"開什麼玩笑！你想怎樣就怎樣嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어차피 네놈의 그 웃기지도 않는 계획은 여기서 박살 날 테니까 승낙하고 말고 할 것도 없어!","JPN":"あんたのそのふざけた計画は、どうせここで阻止するんだから、承諾も何もないよ！","ENG":"This is where your preposterous plan ends, so I won't have to answer to that ridiculous question.","TWN":"反正你們那無聊的計畫就會在這裡結束，同不同意都無所謂！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"유감이지만 저도 마찬가지입니다.","JPN":"残念ながら、僕も同じです。","ENG":"I'm sorry but I'll have to agree with her.","TWN":"很遺憾，我也一樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 짓을 했다간 스승님께 무슨 잔소리를 들을지 모르겠거든요.","JPN":"そんなことしたら、師匠にどんな説教を浴びせられるかわかりませんからね。","ENG":"I can't even begin to think what Master would say to me if I did something like that.","TWN":"我要是做出那種事情，真不知道師父會念些什麼呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그런가...... 그럼 협상은 결렬이로군.","JPN":"そうか……では、交渉決裂だな。","ENG":"I see... The deal's off then.","TWN":"這樣啊……那交涉失敗了呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그렇다면 나 역시 전력을 다해 자네들을 쓰러뜨리고 프로젝트 테라사이드를 완수할 수밖에.","JPN":"だったら、私も全力で君たちを倒し、プロジェクトテラサイドを完遂するしかない。","ENG":"I have no choice but to defeat you and complete Project Terraside.","TWN":"那麼我就只有全力擊敗你們，完成特拉賽德計畫了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>불멸체 코어 서브 프로세스 재할당</color>","JPN":"<color=#ffd34c>不滅体コア、サブプロセスに再割り当て</color>","ENG":"<color=#ffd34c>Immortal System Core sub-process reallocated.</color>","TWN":"<color=#ffd34c>不滅者核心子程序再發送</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>리플레이서 엘리트 및 중화력 지원형 붕괴제 긴급 재생 시퀀스 가동</color>","JPN":"<color=#ffd34c>リプレイサーエリートおよび重火力支援型の崩壊剤、緊急再生シーケンスを稼動</color>","ENG":"<color=#ffd34c>Starting emergency regeneration of Replacer Elites and heavily armed supporter type collapsers.</color>","TWN":"<color=#ffd34c>克隆集團精英與重火力支援型崩潰體緊急再生程序啟動</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L19_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_NULL","text":{"KOREA":"크르륵...... 적은...... 적은 어디에 있지?","JPN":"グルル……敵は……敵はどこだ？","ENG":"Grrrrr... Enemies... Where are my enemies?","TWN":"唔啊啊……敵人……敵人在哪裡？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_METAMOR_01"},{"id":"L20_1","type":"dialog","speaker":"REPLACER_REPLACER_NULL_NULL","text":{"KOREA":"적을...... 분쇄한다......!","JPN":"敵を……粉砕する……！","ENG":"Enemies shall be... eliminated!","TWN":"消滅……敵人……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REPLACER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야 이것들은? 갑자기 어디서 나타난 거지?","JPN":"な、なに、こいつら？　どこから現れたの？","ENG":"W-what are these? Where did they come from?","TWN":"這、這些傢伙是怎麼回事？突然從那裡冒出來的啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기에 있던 리플레이서 병력들은 모두 재료로 사용된 거 아니었어?","JPN":"ここにいたリプレイサー兵は、全員材料になったんじゃなかった？","ENG":"Weren't all the Replacer forces here already consumed as material?","TWN":"這裡的克隆集團兵力不是全都被當成材料了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마도 우릴 상대하기 위해 불멸체 코어로 임시 재생체를 만들어 낸 모양이군요.","JPN":"おそらく僕たちの相手をさせるために、不滅体コアで仮の再生体を作りだしたようです。","ENG":"It seems they've temporarily produced regenerated Replacers with the Immortal System Core.","TWN":"大概是為了對付我們，用不滅者核心製造出的臨時再生體吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"조심하세요, 미나 양.","JPN":"ご用心を、ミナさん。","ENG":"Be careful, Mina.","TWN":"小心，米娜小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저것들은 기존 리플레이서의 전투경험을 집약해서 만든 방어 병력일 겁니다.","JPN":"あれらは、既存のリプレイサーの戦闘経験を集約して作りだした防御部隊でしょう。","ENG":"We'll be dealing with defensive forces created with all the combat memories the Syndicate has accumulated.","TWN":"他們是集合了克隆集團既存的戰鬥經驗，被創造出來的防禦兵力。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어쩌면 거의 간부급에 준하는 전투력을 가지고 있을 수도 있어요.","JPN":"ひょっとすると、幹部級に順ずる戦闘力を持っているかもしれません。","ENG":"They could be as powerful as officers.","TWN":"他們大概有著與幹部不相上下的戰鬥力。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이래 봬도 자네들이 태어나기도 전부터 침식체들과 싸워 온 몸이지.","JPN":"こう見えても、君たちが生まれる前から侵食体と戦ってきたんだ。","ENG":"I've fought C.O.s since before you were even born.","TWN":"別看我這樣，我可是在你們出生前，和侵蝕體一路戰鬥過來的人。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그리 호락호락하게 당해주진 않을 테니까...... 각오하도록.","JPN":"簡単にやられはしない……覚悟しろ。","ENG":"You shouldn't expect that I'd go down so easily. Brace yourselves.","TWN":"我是不會這麼輕易就被打敗的……做好覺悟吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};